-- =========================================================
-- Mo-Eats strict dummy seed generated from 5 JSON sources
-- 기준: 01 + 02 + 03 구조 / 메뉴 카테고리 필수 생성 / 이미지 없는 메뉴 제외 / UTF-8 비파손
-- 생성일: 2026-04-02
-- =========================================================
SET NAMES utf8mb4;
USE moeats;

SET FOREIGN_KEY_CHECKS = 0;
TRUNCATE TABLE menu_image;
TRUNCATE TABLE store_menu;
TRUNCATE TABLE store_menu_category;
TRUNCATE TABLE store;
SET FOREIGN_KEY_CHECKS = 1;



















































-- =========================================================
-- 검증용 조회
-- =========================================================
SELECT COUNT(*) AS member_count FROM member;
SELECT COUNT(*) AS store_count FROM store;
SELECT store_category, COUNT(*) AS store_cnt FROM store GROUP BY store_category ORDER BY store_category;
SELECT COUNT(*) AS menu_category_count FROM store_menu_category;
SELECT COUNT(*) AS store_menu_count FROM store_menu;
SELECT COUNT(*) AS menu_image_count FROM menu_image;
SELECT s.store_name, COUNT(sm.menu_idx) AS menu_cnt
  FROM store s
  LEFT JOIN store_menu sm ON s.store_idx = sm.store_idx
 GROUP BY s.store_idx, s.store_name
 ORDER BY menu_cnt DESC, s.store_name ASC
 LIMIT 20;