INSERT INTO store_menu (menu_idx, store_idx, menu_category_idx, menu_name, menu_description, menu_price, menu_status, display_order) VALUES
(1, 1, 1, '망고 요구르트 L', '[추천] Sugar30% / Regular Ice (얼음 보통)', 5500, 'AVAILABLE', 1),
(2, 1, 2, '말차 카스테라 샌드 + 아메리카노 L', '부드러운 말차 카스텔라와 함께 즐기는 아이스 아메리카노 SET', 9600, 'AVAILABLE', 2),
(3, 1, 2, '리얼 퍼지 브라우니 + 아메리카노 L', '진한 초콜릿 풍미와 꾸덕하고 밀도높은 퍼지 브라우니와 아메리카노 SET', 8600, 'AVAILABLE', 3),
(4, 1, 2, '솔티드 카라멜 크림 라떼 L', '커피의 깊은 풍미에 단짠 솔티드를 더해 부드러운 밀크폼과 함께 즐길 수 있는 공차 시즌 커피', 6100, 'AVAILABLE', 4),
(5, 1, 2, '공차 머쉬룸 수프 + 아메리카노L', '양송이 버섯의 진한 풍미로 즐기는 식사 대용 수프 + 아이스아메리카노', 8500, 'AVAILABLE', 5),
(6, 1, 2, '아메리카노L & 밀크티 롤 크레이프', '아메리카노와 함께 즐기는 고소한 풍미의 크레이프 안에 시원한 밀크티 크림이 가득한 케이크', 10100, 'AVAILABLE', 6),
(7, 1, 2, '아메리카노1L+초코칩청크쿠키', '1리터 아이스아메리카노와 달콤한 쿠키를 함께 즐기는 SET 메뉴', 9400, 'AVAILABLE', 7),
(8, 1, 2, '솔티드 카라멜 크림 라떼 L + 스모어 쫀득바', '단짠 크림 라떼와 함께 즐기는 쫀득 꾸덕한 버터바', 11000, 'AVAILABLE', 8),
(9, 1, 2, '솔티드 카라멜 크림 라떼 L + 황치즈 쫀득바', '단짠 크림 라떼와 함께 즐기는 쫀득 꾸덕한 황치즈 버터바', 11000, 'AVAILABLE', 9),
(10, 1, 2, '아메리카노 J + 그릴드핫치킨브리또', 'SET) 구운 핫치킨과 갈릭라이스, 모짜렐라 치즈가 듬뿍 들어간 브리또 + 아메리카노 J', 10100, 'AVAILABLE', 10),
(11, 1, 2, '아메리카노 L + 아이스 밀크티 펄 케이크', '쪽득한 펄이 올라간 밀크티 케이크와 아이스 아메리카노를 함께 즐기는 SET 메뉴', 10100, 'AVAILABLE', 11),
(12, 1, 2, '아이스 아메리카노 1L', '대용량 1리터로 즐기는 공차 아이스 아메리카노', 7000, 'AVAILABLE', 12),
(13, 1, 2, '카페라떼 1L', '대용량으로 즐기는 공차 아이스 카페라떼', 11000, 'AVAILABLE', 13),
(14, 1, 2, '아메리카노 L', '[추천] Sugar0% / Ice고정', 4200, 'AVAILABLE', 14),
