(31, 1, 2, 'HOT 바닐라 카페라떼 J', '[추천] Sugar50%', 6100, 'AVAILABLE', 31),
(32, 1, 3, '사리곰탕 펄국(조리)', '깊고 진한 사리곰탕 국물에 대왕 타피오카 펄과 쫄깃한 분모자 펄을 더한, 새해맞이 설날 한정 펄국', 3400, 'AVAILABLE', 32),
(33, 1, 3, '사리곰탕 펄국(비조리)', '깊고 진한 사리곰탕 국물에 대왕 타피오카 펄과 쫄깃한 분모자 펄을 더한, 새해맞이 설날 한정 펄국', 3400, 'AVAILABLE', 33),
(34, 1, 3, '사리곰탕 펄국+망고 요구르트L', '깊고 진한 사리곰탕 펄국과 상큼한 망고 요구르트와의 환상 조합 (추천당도 30%)', 8900, 'AVAILABLE', 34),
(35, 1, 3, '신라면툼바 펄볶이(조리)', '펄볶이는 배달로 주문 시 넘침을 방지하기 위하여, 별도의 용기에 제공됩니다.', 3400, 'AVAILABLE', 35),
(36, 1, 3, '신라면툼바 펄볶이 + 망고요구르트', '매콤꾸덕한 신라면 툼바 펄볶이와 상큼한 망고 요구르트와의 환상 조합 (펄볶이 별도 제공)', 8900, 'AVAILABLE', 36),
(37, 1, 3, '펄볶이 듀엣(조리)', '(오리지널+짜장)펄볶이는 배달로 주문 시 넘침을 방지하기 위하여, 별도의 용기에 제공됩니다.', 5800, 'AVAILABLE', 37),
(38, 1, 3, '오리지널 펄볶이(조리)', '펄볶이는 배달로 주문 시 넘침을 방지하기 위하여, 별도의 용기에 제공됩니다.', 2800, 'AVAILABLE', 38),
(39, 1, 3, '오리지널 펄볶이(비조리)', '비조리상품)냉동상태로 제공됩니다. 전자레인지 1분30초 조리 후 익힘 정도를 확인해 주세요', 2800, 'AVAILABLE', 39),
(40, 1, 3, '미니펄 망고밀크 + 리얼망고 L', '[추천] Sugar50% / Ice고정', 6500, 'AVAILABLE', 40),
(41, 1, 3, '미니펄 망고밀크 + 리얼망고 J', '[추천] Sugar50% / Ice고정', 7600, 'AVAILABLE', 41),
(42, 1, 3, '망고요구르트+화이트펄 L', '[추천] Sugar0% / Regular Ice (얼음 보통)', 6200, 'AVAILABLE', 42),
(43, 1, 3, '망고요구르트+화이트펄 J', '[추천] Sugar0% / Regular Ice (얼음 보통)', 7500, 'AVAILABLE', 43),
(44, 1, 3, 'HOT 카페 모카 L', '[추천] Sugar50%', 5000, 'AVAILABLE', 44),
(45, 1, 3, 'HOT 카페 모카 J', '[추천] Sugar50%', 6100, 'AVAILABLE', 45),
(46, 1, 3, '멜팅 치즈 포켓 샌드', NULL, 3400, 'AVAILABLE', 46),
(47, 1, 3, '스틱 치즈케익', '순수한 맛과 깊은 풍미의 끼리 프리미엄 크림치즈를 이용한 부드럽고 깊은 맛을 즐길 수 있는 스틱 형태의 프리미엄 치즈케익', 3100, 'AVAILABLE', 47),
(48, 1, 3, '우유 공빵', NULL, 2300, 'AVAILABLE', 48),
(49, 1, 4, '망고 쥬스 L', '[추천] Sugar30% / Regular Ice (얼음 보통)', 5100, 'AVAILABLE', 49),
(50, 1, 4, '망고 쥬스 J', '[추천] Sugar30% / Regular Ice (얼음 보통)', 6200, 'AVAILABLE', 50),
(51, 1, 5, '더블 말차 밀크티 L', '향긋한 자스민티와 달콤 쌉싸름한 말차를 함께 즐기는 밀크티 (추천 당도 0%)', 5900, 'AVAILABLE', 51),
(52, 1, 5, '얼그레이 말차 밀크티 + 펄 L', '향긋한 얼그레이티에 달콤 쌉싸름한 말차와 쫀득한 펄을 더한 밀크티 (추천 당도 50%)', 6100, 'AVAILABLE', 52),
(53, 1, 5, '그릭요거티 & 자몽 망고 미니펄 크러쉬 L', '그릭요거트에 달콤한 망고와 상큼한 자몽이 더해진 크러쉬', 7000, 'AVAILABLE', 53),
(54, 1, 5, '블랙밀크티+펄 L', '[추천] Sugar50% / Regular Ice (얼음 보통)', 5500, 'AVAILABLE', 54),
(55, 1, 5, '타로밀크티+펄 L', '[추천] Sugar50% / Regular Ice (얼음 보통)', 5500, 'AVAILABLE', 55),
(56, 1, 5, '그릭요거티 & 피치 크러쉬 L', '복숭아의 달콤함과 자스민티의 은은함 위에 꾸덕한 그릭데이 요거트를 얹은 크러쉬', 7000, 'AVAILABLE', 56),
(57, 1, 5, '그릭요거티 & 펄 크러쉬 L', '깊고 진한 얼그레이 밀크티 위에 꾸덕한 그릭데이 요거트를 얹은 크러쉬', 6800, 'AVAILABLE', 57),
(58, 1, 5, '그릭요거티 & 망고 크러쉬 L', '달콤한 망고와 깔끔한 자스민티 향에 꾸덕한 그릭데이 요거트를 얹은 크러쉬', 7000, 'AVAILABLE', 58),
(59, 1, 5, '그릭요거티 & 딸기 크러쉬 L', '상큼한 딸기 과육 위에 꾸덕한 그릭데이 요거트를 얹은 크러쉬', 7000, 'AVAILABLE', 59),
(60, 1, 5, '그릭요거티 & 자몽크러쉬', '달콤 쌉싸름한 자몽에 꾸덕한 그릭데이 그릭요거트가 더해진 크러쉬', 7000, 'AVAILABLE', 60),
(61, 1, 5, '말차샷 타로 밀크티 L', '고소한 타로 밀크티에 쌉싸름한 말차 샷이 어우러진 부드럽고 달콤한 프리미엄 밀크티 (추천당도 50%)', 6100, 'AVAILABLE', 61),
(62, 1, 5, '말차 초코 스무디 L', '달콤한 초코 스무디에 말차폼이 어우러진 부드럽고 달콤한 프리미엄 스무디 (당도 고정)', 6200, 'AVAILABLE', 62),
(63, 1, 5, 'HOT 더블 말차 밀크티 L', '향긋한 자스민티와 달콤 쌉싸름한 말차를 함께 즐기는 밀크티 (추천 당도 0%)', 5900, 'AVAILABLE', 63),
(64, 1, 5, '자스민 코코 with 말차폼 L', '산뜻한 코코넛워터에 자스민티와 말차폼을 더해 함께 즐기는 티 (추천 당도 50%)', 5600, 'AVAILABLE', 64),
(65, 1, 5, '말차 카스테라 샌드', '부드러운 말차 카스테라 사이 진한 말차 크림을 샌드한 케이크', 5400, 'AVAILABLE', 65),
(66, 1, 5, '말차 카스테라 샌드 + 더블 말차 밀크티 L', '부드러운 말차 카스테라 함께 즐기는 달콤 쌉싸름한 말차 밀크티 SET (추천 당도 0%)', 11300, 'AVAILABLE', 66),
(67, 1, 5, '두바이 쫀득 초콜릿 크러쉬 L', '진한 다크초콜릿 스무디에 바삭한 카다이프와 피스타치오, 쫀득한 펄을 갈아내 공차만의 스타일로 재현해낸 두바이 쫀득쿠키 스무디', 6600, 'AVAILABLE', 67),
