(570, 13, 61, '고식이섬유&저당 곡물식빵', '식이섬유가 풍부한 고대곡물 호라산밀과 밀기울로 만들어 건강함 UP, 촉촉한 식감과 고소한 풍미가 매력적인 곡물식빵', 5300, 'AVAILABLE', 89),
(571, 13, 61, '고단백현미식빵', '탕종법을 사용해 촉촉하고 쫄깃한 식감을 살리고, 현미와 호두, 아몬드, 호박씨, 해바라기씨 등 다양한 견과류를 더해 고소하게 즐기기 좋은 고단백 식빵', 3900, 'AVAILABLE', 90),
(572, 13, 61, '데일리우유식빵', '더 부드럽고 더 촉촉해진 신선한 우유맛 가득한 뚜레쥬르 프리미엄 우유식빵 유통기한은 최적의 품질 유지기한이며, 판매가 허용되는 기한입니다. 취식 가능기한은 보관방법에 따라 달라질 수 있습니다.', 3900, 'AVAILABLE', 91),
(573, 13, 61, '2배 더 진한 우유 식빵', '2배 더 진해진 우유 함량과 우유 탕종으로 보들보들한 빵 결 속에 진한 우유의 고소한 풍미를 가득 담은 우유 식빵', 5800, 'AVAILABLE', 92),
(574, 13, 61, '마구마구 밤식빵(대)', '부드럽고 촉촉한 반죽에 밤다이스와 밤페이스트가 듬뿍 들어가 밤 맛의 풍부함을 한층 업그레이드한 제품', 7500, 'AVAILABLE', 93),
(575, 13, 61, '生生생크림식빵', '마스카포네 생크림을 넣어, 극강의 부드러움과 마지막까지 은은한 단맛을 느낄수있는 뚜레쥬르 대표식빵', 5700, 'AVAILABLE', 94),
(576, 13, 61, '폭신폭신우유브레드', '물 한방울도 넣지 않고 우유로만 반죽하여 구워내 폭신폭신하고 담백한 맛이 좋은 빵', 4300, 'AVAILABLE', 95),
(577, 13, 61, '기본좋은 쌀 베이글', '국내산 쌀로 만든 쌀 탕종과 쌀 발효당으로 더 쫄깃하고 촉촉하게 구워낸 쌀 베이글', 3200, 'AVAILABLE', 96),
(578, 13, 61, '호두 연유 바게트', '바삭한 식감의 호두 바게트에 연유크림을 더해 달콤하게 즐기는 간식형 바게트', 4900, 'AVAILABLE', 97),
(579, 13, 61, '밤이 듬뿍 맘모스(대)', '담백한 빵 속에 달콤한 단팥 앙금, 부드러운 크림, 아삭아삭 달콤한 밤과 고구마가 듬뿍 들어간 속이 꽉 찬 간식빵', 6500, 'AVAILABLE', 98),
(580, 13, 61, '진한 크림치즈빵', '우유 초죽을 넣어 촉촉하면서 부드러운 식감을 살리고 크림치즈 본연의 맛을 살린 간식빵', 3000, 'AVAILABLE', 99),
(581, 13, 61, '슈크림빵', '부드럽고 풍부한 맛의 프리미엄 슈크림이 들어간 간식빵', 2100, 'AVAILABLE', 100),
(582, 13, 61, '부드러운후레쉬크림샌드빵', '달콤하고 부드러운 버터크림이 사이사이에 듬뿍 샌드된 부드러운 간식빵/크림속 검은 반점은 바닐라씨드로 안심하고 드시길 바랍니다.', 6700, 'AVAILABLE', 101),
(583, 13, 61, '리얼초코소라빵', '소라모양의 빵에 진한 초코크림이 들어있는 간식빵', 3000, 'AVAILABLE', 102),
(584, 13, 61, '까까웨뜨', '바삭한 패스트리결을 얹은 부드러운 빵 속에 고소한 땅콩크림이 샌드된 간식빵', 2300, 'AVAILABLE', 103),
(585, 13, 61, '낙엽소시지브레드', '하나씩 떼어먹는 재미가 있는 낙엽모양의 소시지 브레드', 3500, 'AVAILABLE', 104),
(586, 13, 61, '소시지쌍쌍브레드', '두개가 나란히 붙어있어 둘이서 나누어 먹기 좋은 소시지 빵', 3200, 'AVAILABLE', 105),
(587, 13, 61, 'NEW어니언소시지포카치아', '부드럽고 쫄깃한 포카치아와 머스터드, 크리스피 어니언이 토핑 된 소세지를 함께 즐길 수 있는 든든한 간식빵', 3100, 'AVAILABLE', 106),
(588, 13, 61, '소금버터롤', '프랑스산 발효 버터의 고소함과 소금의 건강한 찐맛의 조화에 술술 들어가는 식사빵', 2800, 'AVAILABLE', 107),
(589, 13, 61, '바삭 마늘빵(5개입)', '마늘의 향긋함과 버터의 고소한 맛을 그대로 담은 바삭한 식감의 마늘 바게트', 3200, 'AVAILABLE', 108),
(590, 13, 61, '프랑스 바게트', '프랑스산 밀가루가 들어가 겉은 더 바삭하고 속은 더 촉촉한, 구수한 맛의 정통 바게트', 4900, 'AVAILABLE', 109),
(591, 13, 61, '더블 롤치즈 식빵(소)', '폭신하고 부드러운 탕종반죽에 고소한 롤치즈와 짭짤한 체다치즈가 콕콕 한번 먹으면 또 생각나는 더블 롤치즈 식빵', 4500, 'AVAILABLE', 110),
(592, 13, 61, '달콩찹쌀브레드', '고소한 곡물빵과 달콤한 콩, 쫄깃한 찰떡이 조화롭게 어우러지는 든든한 제품', 4700, 'AVAILABLE', 111),
(593, 13, 61, '깨찰빵', '쫄깃한 타피오카전분과 고소한 검은깨 맛을 볼 수 있는 깨찰빵', 1800, 'AVAILABLE', 112),
(594, 13, 61, '단팥빵', '통팥앙금을 사용하여 누구나 좋아하는 빵', 2100, 'AVAILABLE', 113),
(595, 13, 61, '소보로빵', '고소한 땅콩과 소보로가 토핑된 간식빵', 2100, 'AVAILABLE', 114),
(596, 13, 61, '오리지널 커피번', '진하고 깊은 커피향과 버터 커스터드 내용물을 더해 한층 업그레이드한 커피번', 3300, 'AVAILABLE', 115),
(597, 13, 61, 'THE 부드러운 카스테라', '꿀을 넣어 더 부드럽고 촉촉하게 입안에서 사르르 녹는 카스테라', 2900, 'AVAILABLE', 116),
(598, 13, 61, '완두앙금빵', '달콤하고 부드러운 완두앙금을 듬뿍 넣어, 남녀노소 좋아하는 간식빵', 2100, 'AVAILABLE', 117),
(599, 13, 61, '초코마카롱도넛', '초콜릿과 초코마카롱 후레이크를 듬뿍 얹은 달콤한 도넛', 2500, 'AVAILABLE', 118),
(600, 13, 61, '딸기마카롱도넛', '화이트초코에 딸기마카롱 후레이크를 듬뿍 얹은 달콤한 도넛', 2500, 'AVAILABLE', 119);
INSERT INTO store_menu (menu_idx, store_idx, menu_category_idx, menu_name, menu_description, menu_price, menu_status, display_order) VALUES
(601, 13, 61, '슈거 글레이즈 도넛', '부드러운 도넛에 달콤한 슈거글레이즈를 디핑한 제품', 2500, 'AVAILABLE', 120),
(602, 13, 61, '조청 왕꽈배기', '우리쌀을 더해 더 쫄깃하고, 조청으로 은은한 단맛과 쌀크런치 토핑으로 씹는 재미까지 더한 추억의 왕꽈배기', 3500, 'AVAILABLE', 121),
(603, 13, 61, '옛날 꽈배기 도넛', '부드럽고 폭신한 식감의 달콤한 추억의 꽈배기', 2100, 'AVAILABLE', 122),
(604, 13, 61, '옛날 단팥 도넛', '부드럽고 폭신한 도넛 속 단팥 앙금이 듬뿍 들어있는 달콤한 추억의 도넛', 2300, 'AVAILABLE', 123),
(605, 13, 61, '생크림버터 스콘', '생크림을 넣어 부드럽고, 버터의 풍미가 가득한 고소하고 담백한 스콘', 4700, 'AVAILABLE', 124),
(606, 13, 61, '호두카라멜 스콘', '고소한 호두와 은은한 카라멜의 단맛이 조화로운 스콘', 4700, 'AVAILABLE', 125),
(607, 13, 62, '스트로베리퀸(15cm)', '반짝이는 비즈로 감싼 부드러운 화이트시트에 상큼달콤한 딸기 꿀리를 샌드하고 신선한 생딸기를 가득 올린 생크림 맛집 뚜레쥬르의 시그니처 케이크 상기 이미지는 계절 및 매장에 따라 디자인이 변경될 수 있습니다.', 38000, 'AVAILABLE', 126),
(608, 13, 62, '카라멜부케(13cm)', '촉촉한 화이트 시트에 카라멜 크림을 샌드하고, 그 위를 사랑스러운 핑크빛 장미와 리본으로 장식한 부케 모양의 미니 케이크', 23000, 'AVAILABLE', 127),
(609, 13, 62, '초코행성 지구인 (12cm)', '헤이즐넛 크림과 초코 크림을 샌드하고 크런치 초코로 코팅해 우주행성을 탐험하는 지구인의 모습을 귀엽게 표현한 쁘띠 케이크', 24000, 'AVAILABLE', 128),
(610, 13, 62, '쇼콜라 하트(15cm)', '초코시트에 달콤하고 진한 초코크림을 샌드하고 바삭한 초콜릿으로 코팅한 하트모양의 러블리한 케이크', 28000, 'AVAILABLE', 129),
(611, 13, 62, '러블리 생크림 케이크(13cm)', '촉촉한 쉬폰 시트에 마스카포네 생크림과 상큼한 딸기 콤포트를 샌드하고 생딸기와 핑크 리본으로 장식한 미니 케이크 상기 이미지는 계절 및 매장에 따라 디자인이 변경될 수 있습니다.', 24000, 'AVAILABLE', 130),
(612, 13, 62, '주토피아2 닉 피넛초코케이크(15cm)', '초코 시트에 달콤하고 고소한 피넛버터 초코 크림이 샌드되어 있는 귀여운 닉 모양 케이크', 30000, 'AVAILABLE', 131),
(613, 13, 62, '헬로카봇스타가디언케이크(21cm)', '헬로카봇 시즌 15의 메인 캐릭터 스타가디언이 빅토리검을 활용해 전투하는 모습을 담은 초코 케이크', 43000, 'AVAILABLE', 132),
(614, 13, 62, '쿠키 바닐라 생크림 케이크(12cm)', '눈을 사로잡는 블랙 화이트 크림 레이어에 진하고 풍미깊은 가나슈와 달콤한 쿠키 크럼블을 샌딩한 바닐라 생크림 케이크', 23000, 'AVAILABLE', 133),
(615, 13, 62, '딸기와우유생크림1호(15cm)', '부드럽고 촉촉한 화이트시트에 풍부한 맛의 생크림과 상큼한 과일로 장식한 생크림 케이크 상기 이미지는 계절 및 매장에 따라 디자인이 변경될 수 있습니다.', 33000, 'AVAILABLE', 134),
(616, 13, 62, '딸기와 우유생크림 2호(18cm)', '부드럽고 촉촉한 화이트시트에 풍부한 맛의 생크림과 상큼한 과일로 장식한 생크림 케이크 (2호사이즈) 상기 이미지는 계절 및 매장에 따라, 디자인이 변경될 수있습니다.', 37000, 'AVAILABLE', 135),
(617, 13, 62, '오,해피 복숭아 케이크(18cm)', '촉촉한 화이트시트에 아삭아삭한 복숭아와 복숭아 생크림을 샌드하여 향긋한 복숭아맛을 가득 느낄 수 있는 생크림 케이크', 36000, 'AVAILABLE', 136),
(618, 13, 62, '쇼콜라갸또(18cm)', '초코시트와 블랙초코시트에 가나슈 초코버터크림으로 샌드하고 초코 글라사쥬로 장식한 케이크', 36000, 'AVAILABLE', 137),
(619, 13, 62, '클래식 오브 치즈케이크(20cm)', '엄선한 자연치즈의 진한 풍미가 그대로 살아있는 부드럽고 촉촉한 수플레 타입의 클래식 치즈 케이크', 35000, 'AVAILABLE', 138),
(620, 13, 62, '뚜초케(두바이스타일초코케이크)', '톡 하고 깨먹고, 바삭하게 즐기고, 가득 한입에 떠먹는 뚜레쥬르 두바이스타일 미니 초코 케이크(1개입)', 19900, 'AVAILABLE', 139),
(621, 13, 62, '쇼콜라갸또(조각)', '초코시트와 블랙초코시트에 가나슈 초코버터크림으로 샌드하고 초코 글라사쥬로 장식한 케이크', 6300, 'AVAILABLE', 140),
(622, 13, 62, '클래식 오브 치즈케이크(조각)', '엄선한 자연치즈의 진한 풍미가 그대로 살아있는 부드럽고 촉촉한 수플레 타입의 클래식 치즈 케이크', 6300, 'AVAILABLE', 141),
(623, 13, 62, '쇼콜라 생크림(조각)', '진한 초콜릿 풍미의 발로나 가나슈 무스와 부드러운 생크림, 바삭한 크런치 볼의 식감이 어우러지는 조각 케이크', 6700, 'AVAILABLE', 142),
(624, 13, 62, '쁘띠복숭아케이크', '촉촉한 화이트시트에 아삭아삭한 복숭아 생크림을 샌드하여 향긋한 복숭아맛을 가득 느낄 수 있는 디저트 케이크', 8300, 'AVAILABLE', 143),
(625, 13, 62, '사르르 고구마케이크 빵', '고구마를 닮은 빵에 부드러운 크림과 고구마 필링이 듬뿍 들어 있어 입 안에서 사르르 녹는 빵', 3800, 'AVAILABLE', 144),
(626, 13, 62, '패스트리에 빠진 에그푸딩', '버터 풍미 가득한 바삭한 패스트리에 달콤하고 부드러운 에그푸딩 내용물과 맛을 올려줄 밀크 카라멜을 더한 제품', 3800, 'AVAILABLE', 145),
(627, 13, 62, '초코청크머핀', '진한 초코청크와 초코 크럼블이 듬뿍 들어간 머핀', 4500, 'AVAILABLE', 146),
(628, 13, 62, '아몬드밀크 초코볼', '품질 좋은 아몬드를 리얼 초콜릿으로 코팅해 달콤한 초콜릿과 고소한 아몬드의 맛이 황금비율로 어우러진 아몬드 초코볼', 12000, 'AVAILABLE', 147),
(629, 13, 62, '새콤달콤 그대로 딸기칩', '국내산 딸기를 사용하여 그대로 동결건조한 과육의 맛과 향을 그대로 살린 새콤달콤 딸기칩', 4300, 'AVAILABLE', 148),
