(741, 18, 84, '쫀득튀김 두바이소금빵 (카다이프면x,수제크런키+소금빵)', '몽파의 소금빵 중 인기탑 메뉴 두바이 소금빵 몽블랑 드 파리 두바이 구매안내 1. 피스타치오 스프레드 피스타치오 직접 탈각 AOP 인증 프랑스 레스큐어 버터 사용 로스팅 신선하고 퀄리티 높은 피스타치오 스프레드피스타치오 함량 50%이상 사용 (시중 유통상품 평균 30%대) 2. 카다이프 대체 프랑스산 AOP 인증 레스큐어 최상급 버터 한국, 미국, 캐나다에서 생산되는 밀, 곡물을 사용 직접 수제로 매일 뽁고 튀겨서 만들어지는 수제곡물 크런키+빵 을 적절하게 배합한 빠삭한 식감의 레시피 활용 최상급 재료와 땀으로 신선하게 만들어진 상품 제공 좋은 재료와 당일 직접 수작업으로 만들어내는 노력으로 퀄리티 업/바삭한 식감과 맛이 있는 두바이 메뉴들은 위 재료들을 활용하여 만들어진 제품들을 고객분 들에게 제공이 됩니다. 카다이프 면으로 생각하시어 요청되는 반품 되지 않으니 구매 전 내용 읽고 숙지해주세요.', 8300, 'AVAILABLE', 25),
(742, 18, 84, '복숭아 아이스티(ICE ONLY)', '달달하고 부담없이 드실 수 있는 갈증해소 음료', 4800, 'AVAILABLE', 26),
(743, 18, 84, '유자차(HOT ONLY)', '겨울에 즐기기 좋은 따뜻한 달콤상큼 유자차', 4800, 'AVAILABLE', 27),
(744, 18, 84, '얼그레이(HOT ONLY)', '베르가못 향이 은은하게 퍼지는 클래식 얼그레이 티', 5800, 'AVAILABLE', 28),
(745, 18, 84, '캐모마일(HOT ONLY)', '깊고 향긋한 캐모마일 향이 나는 허브티', 5800, 'AVAILABLE', 29),
(746, 18, 85, '튀김 라이언 크림 소금빵(1인분)', '화이트초콜릿+요거트+소금빵', 5800, 'AVAILABLE', 30),
(747, 18, 85, '화이트초코요거트(1통)', NULL, 2000, 'AVAILABLE', 31),
(748, 18, 85, '푸른피 쫀득볼(1인분)', '요거트베이스 + 화이트초코 + 초코볼 + 수제마시멜로', 7500, 'AVAILABLE', 32),
(749, 18, 86, '프랜치 토스트', NULL, 11800, 'AVAILABLE', 33),
(750, 18, 86, '프렌치 두바이 토스트', '(카다이프면X, 수제곡물크런키+빵)', 13800, 'AVAILABLE', 34),
(751, 18, 87, '쫀득튀김 명란마요 소금빵', '레스큐어 버터 풍미와 빵가루 입혀 튀겨낸 소금빵에 짭짤한 명란의 조화, 몽블랑 드 파리의 베스트셀러 튀김 소금빵', 5600, 'AVAILABLE', 35),
(752, 18, 87, '명란 바게트(1개)', '명란 바게트 특성상 소스가 많아서 컷팅배송이 불가함을 당부드립니다', 7800, 'AVAILABLE', 36),
(753, 18, 87, '튀김 레스큐어 소금빵', '레스큐어 버터 풍미가 가득한 몽블랑드파리 스테디셀러 소금빵을 빵가루 입혀 튀겨낸 튀김소금빵', 3800, 'AVAILABLE', 37),
(754, 18, 87, '쫀득튀김 글레이즈 소금빵', '레스큐어 버터 풍미와 달달한 글레이즈가 만나 단짠의 조합이 환상적인 소금빵을 빵가루 입혀 튀겨낸 튀김 소금빵', 4600, 'AVAILABLE', 38),
(755, 18, 87, '쫀득튀김 소금빵 앙버터(1개)', '빵가루를 입힌 소금빵을 카놀라유에 튀겨 통팥앙금과 국내산 찹쌀을 넣어 달콤 쫀득한 튀김 소금빵', 6800, 'AVAILABLE', 39),
(756, 18, 87, '쫀득튀김 뿌링클콘치즈 소금빵(1개)', '빵가루를 입힌 소금빵을 카놀라유에 튀겨 국내산 찹쌀과 옥수수 콘, 치즈 그리고 깔끔하고 약간의 매운맛을 내기 위한 신선한 청양고추를 직접 다져 넣은 튀김 소금빵, 그위에 뿌링클 시즈닝', 8200, 'AVAILABLE', 40),
(757, 18, 87, '쫀득튀김 불닭콘치즈소금빵', '소세지와 콘치즈와 오리지널 불닭소스가 어우러진 매운 소금빵을 빵가루를 입혀 튀긴 ''튀김 소금빵''', 7600, 'AVAILABLE', 41),
(758, 18, 87, '쫀득튀김 피자소금빵(1개)', '페파로니와 치즈, 진한 피자 소스, 소금빵을 빵가루 입혀 튀겨낸 한끼 식사 대용으로 좋은 튀김 소금빵', 6600, 'AVAILABLE', 42),
(759, 18, 87, '쫀득튀김 소금빵 플레인(1개)', '빵가루를 입힌 소금빵을 카놀라유에 튀겨 국내산 찹쌀을 넣어 쫀득 단백한 튀김 소금빵', 5800, 'AVAILABLE', 43),
(760, 18, 88, '두바이 버터바(카다이프면X,수제크런키+버터바)', '프랑스 대표 버터, 레스큐어 버터를 사용해 만들어 고급진 풍미와 수제곡물크런키의 바삭한 식감 일품인 최고급 두바이 버터바', 7500, 'AVAILABLE', 44),
(761, 18, 88, '블루 슈가 버터바(1인분)', '초콜릿+버터바', 5800, 'AVAILABLE', 45),
(762, 18, 88, '레스큐어 버터바(1개)', '프랑스 대표 버터, 레스큐어 버터를 사용해 만들어 고급진 풍미와 바삭하게 부서지는 식감이 일품인 최고급 버터바', 4800, 'AVAILABLE', 46),
(763, 18, 88, '메론 쫀득볼(1개)', '메론스프레드 + 마카다미아 + 수제마시멜로', 7500, 'AVAILABLE', 47),
(764, 18, 88, '체리블라썸 쫀득볼(1개)', '크림 브륄레 + 구운 피칸 + 수제 마시멜로', 7500, 'AVAILABLE', 48),
