(807, 20, 94, '찹쌀떡', '추억이 새록새록 뽀얀 찹쌀떡', 4000, 'AVAILABLE', 36),
(808, 21, 95, '피초쿠키 (두바이초콜릿쿠키)', '피스타치오 카다이프가 들어가 바쟉바쟉한 식감이 매력적인 쿠키', 6600, 'AVAILABLE', 1),
(809, 22, 96, '제주 두유호지차라떼', '[시그니처/음료1위] ''제주산 유기농 호지차만 사용합니다.'' 녹차를 한 번 더 달군 차로 카페인이 적고 구수한 맛의 벽돌집 시그니처 라떼입니다. 아이스는 크림(100%동물성)이 더해집니다. 같이 드시면 더 맛있습니다.', 6500, 'AVAILABLE', 1),
(810, 22, 96, '아메리카노', '초콜릿을 한웅큼 집어 삼킨 것 같은 묵직한 초콜릿의 단 맛, 카카오닙스의 쌉쌀함, 헤이즐넛의 고소함, 애프터에서 느껴지는 약간의 우아한 산미', 4800, 'AVAILABLE', 2),
(811, 22, 96, '카페라떼', NULL, 5300, 'AVAILABLE', 3),
(812, 22, 96, '바닐라빈 라떼', '프리미엄 마다가스카르 바닐라빈으로 직접 숙성시켜 만든 시럽이 들어간 풍부한 맛과 향의 라떼입니다.', 6000, 'AVAILABLE', 4),
(813, 22, 96, '딸기라떼(차가운)', '직접 담근 수제 딸기 청으로 만든 딸기라떼입니다. 크림과 같이 섞어드시면 더욱 묵직하고 진한 딸기라떼 맛을 느끼실 수 있습니다. 딸기 청 아끼지 않고 듬뿍 넣어드립니다. (배달 중 크림이 섞일 수 있는 점 양해 바랍니다.)', 6000, 'AVAILABLE', 5),
(814, 22, 96, '레몬 블라썸 차', '수제 꿀레몬청 + 히비스커스 블라썸차의 조합으로 상큼하고 달콤한 차 입니다.', 6000, 'AVAILABLE', 6),
(815, 22, 96, '자몽 허니 얼그레이차', '꿀자몽청+얼그레이차의 조합으로 꿀자몽의 달콤쌉싸름함이 잘 느껴지는 차입니다.', 6000, 'AVAILABLE', 7),
(816, 22, 97, '시나몬 카푸치노', '시나몬 향이 가득한 카푸치노입니다. (향과 맛을 위해 시나몬 시럽이 5g 들어갑니다. 원하지 않으실 경우 요청사항에 적어주세요.)', 5500, 'AVAILABLE', 8),
(817, 22, 97, '피스타치오 라즈베리 파운드', '부드러운 피스타치오 파운드 속에 직접 만든 라즈베리 잼이 가득 들어있습니다. 피스타치오의 묵직한 고소함과 새콤한 라즈베리로 조화가 좋은 파운드입니다.', 4800, 'AVAILABLE', 9),
(818, 22, 97, '발로나 다크초코 파운드', '세계적인 초콜릿 브랜드 발로나사의 카카오파우더와 발로나 다크 초콜릿이 들어간 진한 초콜릿 맛의 파운드입니다.', 4500, 'AVAILABLE', 10),
(819, 22, 97, '레몬파운드', '촉촉하고 부드러운 레몬파운드입니다. 상큼한 레몬 아이싱을 더해 더욱 상큼하고 달콤하게 드실 수 있습니다.', 4500, 'AVAILABLE', 11),
(820, 22, 97, '벽돌집 원두(200g)', '초콜릿을 한웅큼 집어 삼킨 것 같은 묵직한 초콜릿의 단 맛, 카카오닙스의 쌉쌀함, 헤이즐넛의 고소함, 애프터에서 느껴지는 약간의 우아한 산미(원두의 맛과 향을 위해 분쇄는 진행하지 않습니다.)', 13500, 'AVAILABLE', 12),
(821, 22, 98, '토마토 바질 에이드', '매주 신선한 토마토와 농장에서 받는 바질로 청을 만듭니다. 한 알 한 알 껍질 제거하여 부드럽고, 숙성되어 쫀득한 토마토와 같이 드셔보세요. 맛있습니다. (수제 청의 맛을 최대한으로 이끌어낼 수 있게 사이다가 아닌 탄산수로 제조합니다.)', 6500, 'AVAILABLE', 13),
(822, 22, 98, '제주 감귤주스', '(벽돌집X아날로그감귤밭 콜라보 프리미엄 음료입니다.) 유기농 무농약, 무설탕 제주 감귤 착즙 100% 주스입니다. 귤 껍질까지 같이 착즙한 주스로 비타민이 가득한 주스입니다.', 6800, 'AVAILABLE', 14),
(823, 22, 99, '더블 바닐라', '마스카포네 더블 바닐라 무스 (타히티, 마다가스카르) / 바닐라 크렘빠띠시에르 / 바닐라 가나슈 / 비스퀴 조꽁드 / 파트사블레', 8500, 'AVAILABLE', 15),
(824, 22, 99, '호지&밤 바스크치즈케이크(글루텐프리)', '[글루텐프리] 제주 유기농 호지차를 사용한 바스크 치즈케이크입니다. 녹차와는 또 다른 매력의 호지차를 바스크 치즈케이크에 표현해 보았습니다. 녹차를 한 번 더 달궈 쓴맛보다는 고소한 맛이 가득한 호지차 바스크 치즈케이크입니다. 달콤고소한 보늬밤도 콕 박혀있어요', 7800, 'AVAILABLE', 16),
(825, 22, 100, '고르곤졸라치즈 휘낭시에', '피칸테 고르곤졸라치즈가 들어가 고르곤졸라치즈만의 풍미가 환상인 휘낭시에입니다.', 3000, 'AVAILABLE', 17),
(826, 22, 101, '밤 바스크치즈케이크(글루텐프리)', '[벽돌집 시그니처 메뉴] [글루텐프리] 밤 페이스트를 듬뿍 넣어 밤의 향과 맛을 진하게 느끼실 수 있습니다. 보늬 밤이 통으로 넣어 식감의 더했습니다.', 7800, 'AVAILABLE', 18),
(827, 22, 101, '레몬+딜 크림치즈 쿠키', '[레몬+딜의 만남] 레몬향이 가득한 레몬 쿠키 반죽에 레몬+딜 크림치즈가 들어가 상큼함을 2배로 느낄 수 있습니다. 추천드려요', 4500, 'AVAILABLE', 19),
(828, 22, 101, '벽돌집 초코칩 쿠키', '벽돌집 인기 쿠키인 초코칩쿠키는 2가지 견과류 호두+피칸, 3가지종류의 초콜릿 깔리바우트 다크커버춰, 발로나 초코칩, 깔리바우트 청크 초콜릿이 가득 들어간 쿠키입니다.', 4500, 'AVAILABLE', 20),
(829, 23, 102, '생크림단팥빵', '빵장수단팥빵 대표 메뉴 ''생크림 단팥빵'' 고소한 크림이 가득', 3500, 'AVAILABLE', 1),
