(2547, 46, 225, '라떼', '원두 자체의 단맛이 올라오는 라떼 맛집 구트 오피스의 카페라떼', 5000, 'AVAILABLE', 3),
(2548, 46, 225, '바닐라 라떼', '바닐라빈 시럽이 들어간 바닐라빈라떼', 5500, 'AVAILABLE', 4),
(2549, 46, 225, '아인슈패너(ICE)', '적절한 산미의 커피와 고소하고 달콤한 크림의 궁합이 환상인 블랙베이스 아인슈패너', 5500, 'AVAILABLE', 5),
