(2564, 46, 229, '단호박 파운드 케이크(1ps)', '단호박 크림과 크림치즈가 올라간 커피와 먹기 안성맞춤인 파운드 케이크', 4500, 'AVAILABLE', 20),
(2565, 46, 229, '당근케이크', '제주산흙당근 시나몬 당근쨈 크림치즈프로스팅의 조화가 아주 좋은 구트오피스의 또하나 대표디저트입니다', 6800, 'AVAILABLE', 21),
(2566, 46, 229, '말돈소금우유 케이크(1조각)', '부드럽게 사르르 녹는 시트+진한 우유맛 크림+ 말돈소금으로 포인트가 되는 단짠 단짠 케이크 입니다', 6500, 'AVAILABLE', 22),
