(2608, 49, 239, '말차 딸기 라떼', '유기농 말차의 진한 풍미에 달콤하고 상큼한 딸기를 더한 밸런스 좋은 말차 베버리지 음료', 7200, 'AVAILABLE', 1),
(2609, 49, 239, '휘핑크림 카푸치노', '뜨거운 에스프레소와 차가운 휘핑크림이 만나 달콤하고 부드럽게 즐기는 핸즈의 시그니처 메뉴', 5800, 'AVAILABLE', 2),
(2610, 49, 239, '바닐라 라떼', '에스프레소에 핸즈만의 바닐라파우더, 우유를 더해 바닐라의 풍미를 풍부히 즐길 수 있는 메뉴', 6300, 'AVAILABLE', 3),
(2611, 49, 239, '소이 크림 라떼', '몸에 좋은 콩가루에 에스프레소와 우유, 수제휘핑크림이 더해져 달콤함과 고소함이 일품인 메뉴', 6500, 'AVAILABLE', 4),
(2612, 49, 239, '아포가토 클래식', '하겐다즈 바닐라 아이스크림에 진한 풍미의 핸즈 에스프레소를 더해 달콤하고 쌉쌀한 맛의 조화', 7000, 'AVAILABLE', 5),
(2613, 49, 239, '에스프레소 콘빤나', 'Only Hot 진한 에스프레소에 달콤한 수제 휘핑크림을 올린 달콤쌉쌀한 에스프레소 메뉴', 5000, 'AVAILABLE', 6),
(2614, 49, 239, '더치 라떼 멜랑슈', 'Only Iced 진한 농도감의 더치와 부드러운 우유, 솔티드휘핑크림이 조화로운 커피 메뉴', 7000, 'AVAILABLE', 7),
(2615, 49, 240, '베리베리굿와플', '듬뿍 올려진 생딸기와 하겐다즈 아이스크림으로 화려한 비주얼을 자랑하는 찹쌀 와플입니다.', 20300, 'AVAILABLE', 8),
(2616, 49, 240, '초코 바나나 와플', '하겐다즈 초코 아이스크림과 부드러운 바나나가 올라가 달콤함이 배가 되는 초코바나나 찹쌀와플', 14300, 'AVAILABLE', 9),
(2617, 49, 240, '하겐다즈 아이스크림 와플', '쫄깃바삭한 핸즈 찹쌀와플에 2가지맛 하겐다즈 아이스크림과 휘핑크림이 어우러진 시그니처 메뉴', 14300, 'AVAILABLE', 10),
(2618, 49, 240, '블루베리 크림치즈 와플', '블루베리, 수제휘핑크림, 크림치즈, 하겐다즈 바닐라아이스크림이 어우러진 시그니처 찹쌀 와플', 16800, 'AVAILABLE', 11),
(2619, 49, 240, '롱블랙', '핸즈의 탁월한 블렌딩 노하우로 완성된, 진한 농도감 풍부한 향미 긴 여운이 남는 커피 메뉴', 5000, 'AVAILABLE', 12),
(2620, 49, 240, '더치 라샤워', 'Only Iced 풍부한 향미의 더치와 톡톡 쏘는 탄산이 만나 더 특별해진 청량 커피 음료', 5500, 'AVAILABLE', 13),
(2621, 49, 240, '자몽 라샤워', '생 자몽의 상큼함과 톡톡 쏘는 탄산의 청량함을 함께 느낄 수 있는 시원한 음료', 6800, 'AVAILABLE', 14),
(2622, 49, 240, '레몬 라샤워', '생 레몬의 상큼함과 톡톡 쏘는 탄산의 청량함을 함께 느낄 수 있는 시원한 음료', 6800, 'AVAILABLE', 15),
(2623, 49, 241, '자몽 착즙티', '생 자몽을 착즙하여 생과육이 듬뿍 들어간, 비타민 C가 풍부한 티/주스 메뉴', 6800, 'AVAILABLE', 16),
(2624, 49, 241, '레몬 착즙티', '생 레몬을 착즙하여 생과육이 듬뿍 들어간, 비타민 C가 풍부한 티/주스 메뉴', 6800, 'AVAILABLE', 17),
(2625, 49, 242, '유자 얼그레이 요거트 스무디', '상큼한 요거트 스무디에 달콤한 유자와 얼그레이 티의 향긋함이 어우러진 블렌디드 티 음료', 6800, 'AVAILABLE', 18),
(2626, 49, 242, '유자 얼그레이 티', '밝고 경쾌한 느낌의 유자에 얼그레이 티의 베르가못 향이 우아하게 어우러진 깊이있는 티 음료', 6000, 'AVAILABLE', 19),
(2627, 49, 242, '녹차 프라페', '고소한 우유와 쌉쌀한 녹차, 하겐다즈 녹차 아이스크림을 블렌딩한 진하고 시원한 프라페메뉴', 7000, 'AVAILABLE', 20),
(2628, 49, 242, '제주 그리니시', '제주 거문오름산 유기농 제주 호지차에 레몬 향과 로즈힙을 블렌딩한 싱그러운 그린티', 5500, 'AVAILABLE', 21),
(2629, 49, 242, '제주 퓨어 블랙', '제주 거문오름산 유기농 홍차, 아쌈, 기문, 로즈플라워, 자스민, 라벤더를 블렌딩한 블랙티', 5500, 'AVAILABLE', 22),
(2630, 49, 242, '하모니 오브 허브', '루이보스와 캐모마일, 페퍼민트 3가지 허브가 어우러진 데일리 허브티 (카페인 없음)', 5500, 'AVAILABLE', 23),
(2631, 49, 242, '히비스커스 애플티', '비타민 풍부한 히비스커스 티와 과육이 가득한 사과 필링을 더해 상큼달콤 특별한 티 음료', 6000, 'AVAILABLE', 24),
