(3884, 110, 450, '게살 누룽지 스프', '진~하고 부드러운 게살 스프에 고소하게 구운 누룽지를 올려 속까지 든든해지는 요리입니다.', 35000, 'AVAILABLE', 1),
(3885, 110, 450, '해물 누룽지탕', '다양한 해물과 채소를 듬뿍 넣은 진한 국물에 고소한 누룽지가 속까지 든든하게 채워줍니다!', 45000, 'AVAILABLE', 2),
(3886, 110, 451, '화룡 짜장면', '매 주문마다 바로 볶아내는 진짜 짜장입니다. 재료의 살아있는 식감을 맛볼 수 있습니다.', 8000, 'AVAILABLE', 3),
(3887, 110, 451, '화룡 백짬뽕', '직접 끓인 깊고 감칠맛나는 맑은 닭육수에 칼칼함 한스푼 추가! 해장으로 딱 좋습니다!', 10000, 'AVAILABLE', 4),
(3888, 110, 451, '화룡 짬뽕', '직접 우려낸 진한 육수에 불향 가득 담아낸 얼큰한 국물! 속까지 시원하게 풀리는 맛입니다.', 9000, 'AVAILABLE', 5),
(3889, 110, 451, '해물 쟁반짜장(1인)', '진짜 짜장에 신선한 해물을 볶아 큼직한 쟁반에 내어드립니다!', 10000, 'AVAILABLE', 6),
(3890, 110, 451, '해물 야끼우동', '신선한 해물을 듬뿍 넣고 센 불에 볶아낸 매콤한 소스에 쫄깃한 면발로 입맛을 확 당깁니다!', 10000, 'AVAILABLE', 7),
(3891, 110, 451, '해물 우동', '신선한 해물을 듬뿍 담아내 깊고 시원한 맛으로 누구나 부담없이 즐길 수 있습니다!', 9000, 'AVAILABLE', 8),
(3892, 110, 451, '화룡 볶음밥', '센 불에 빠르게 볶아내 모든 재료가 싱싱하게 살아있고 진짜 짜장을 곁들여 더욱 맛있습니다!', 8000, 'AVAILABLE', 9),
(3893, 110, 452, '중화 국밥', '다양한 재료와 볶음밥이 들어가 푸짐한 국밥 한그릇! 얼큰하고 든든한 화룡식객의 별미입니다.', 11000, 'AVAILABLE', 10),
(3894, 110, 452, '중새우 볶음밥', '볶음밥 위에 통통한 새우튀김과 감칠맛 듬뿍 특제 소스로 푸짐한 프리미엄 볶음밥입니다.', 9000, 'AVAILABLE', 11),
(3895, 110, 452, '게살 볶음밥', '탱글하고 감칠맛 넘치는 게살을 듬뿍 넣어 볶아낸 볶음밥! 깊은 풍미로 누구나 좋아합니다!', 10000, 'AVAILABLE', 12),
(3896, 110, 452, '해물 야끼밥', '신선한 해물을 듬뿍 넣고 센 불에 볶아낸 매콤한 소스와 고슬고슬한 밥은 참을수가 없죠!', 10000, 'AVAILABLE', 13),
(3897, 110, 453, '숙주탕수육(小)', '갓 튀긴 탕수육 위에 아삭한 숙주와 청양고추를 듬뿍올린 화룡식객 특제메뉴입니다!', 20000, 'AVAILABLE', 14),
(3898, 110, 453, '화룡 탕수육(小)', '주문 즉시 튀겨 바삭한 돼지고기에 새콤달콤한 소스를 푹~ 씹을수록 고소한 탕수육입니다!', 18000, 'AVAILABLE', 15),
(3899, 110, 453, '화룡 탕수육(大)', '주문 즉시 튀겨 바삭한 돼지고기에 새콤달콤한 소스를 푹~ 씹을수록 고소한 탕수육입니다!', 28000, 'AVAILABLE', 16),
(3900, 110, 453, '숙주탕수육(大)', '갓 튀긴 탕수육 위에 아삭한 숙주와 청양고추를 듬뿍올린 화룡식객 특제메뉴입니다!', 30000, 'AVAILABLE', 17),
(3901, 110, 453, '칠리 새우(小)', '바삭하게 튀겨낸 탱글한 새우에 특제 칠리소스를 듬뿍! 매콤달콤한 맛이 일품입니다!', 21000, 'AVAILABLE', 18),
(3902, 110, 453, '칠리 새우(大)', '바삭하게 튀겨낸 탱글한 새우에 특제 칠리소스를 듬뿍! 매콤달콤한 맛이 일품입니다!', 35000, 'AVAILABLE', 19),
(3903, 110, 453, '레몬 크림새우(小)', '바삭하게 튀겨낸 탱글한 새우 위에 상큼한 특제레몬크림소스를 더했습니다!', 21000, 'AVAILABLE', 20),
(3904, 110, 453, '레몬 크림새우(大)', '바삭하게 튀겨낸 탱글한 새우 위에 상큼한 특제레몬크림소스를 더했습니다!', 35000, 'AVAILABLE', 21),
(3905, 110, 453, '깐풍기(小)', '바삭하게 튀긴 닭고기에 황비홍을 더해 특제소스로 볶아내 고소함과 매콤함이 일품입니다!', 21000, 'AVAILABLE', 22),
(3906, 110, 453, '깐풍기(大)', '바삭하게 튀긴 닭고기에 황비홍을 더해 특제소스로 볶아내 고소함과 매콤함이 일품입니다!', 35000, 'AVAILABLE', 23),
(3907, 110, 453, '유린기', '겉바속촉 닭튀김에 상큼한 특제소스를 더하고 파채를 듬뿍 올렸습니다!', 21000, 'AVAILABLE', 24),
(3908, 110, 453, '유산슬', '탱글한 새우와 버섯, 신선한 채소들을 센 불에 빠르게 볶아낸 정통 중화요리입니다!', 40000, 'AVAILABLE', 25),
(3909, 110, 453, '게살 유산슬', '푸짐한 유산슬에 탱글하고 감칠맛 터지는 게살+폭신한 머랭 조합으로 무조건 드셔보세요!', 55000, 'AVAILABLE', 26),
(3910, 110, 453, '양장피', '신선한 해산물과 아삭한 채소를 매새콤한 소스에 버무려 입안 가득 상큼한 풍미가 일품입니다', 40000, 'AVAILABLE', 27),
